// Get LLM response content (handles Anthropic langchain node output formats)
const llmRaw = $input.first().json;
const content = llmRaw.output
  || llmRaw.text
  || llmRaw.message?.content
  || llmRaw.content?.[0]?.text
  || '';

// Parse LLM JSON output
let parsed;
try {
  const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('LLM output is not valid JSON: ' + content.substring(0, 300));
}

// Pull normalised complaint fields from Merge node (pre-LLM)
const norm = $('Merge inputs').first().json;

// SLA deadline calculation
const slaHours = { P1: 2, P2: 4, P3: 24 };
const hours = slaHours[parsed.priority_tier] || 24;
const slaDeadline = new Date(Date.now() + hours * 3600000).toISOString();

// Short ticket ID
const ticketId = 'FM-' + Math.random().toString(36).substring(2, 8).toUpperCase();

return [{
  json: {
    source: norm.source,
    raw_complaint: norm.raw_complaint,
    tenant_email: norm.tenant_email,
    tenant_name: norm.tenant_name,
    received_at: norm.received_at,
    ...parsed,
    ticket_id: ticketId,
    sla_deadline: slaDeadline,
    sla_hours: hours
  }
}];

